def f(n):
    if n == 0:
        return 1    # 0! = 1
    return n*f(n-1)

result = f(5)
print(result)

def f(n):
    if n == 1 or n == 2:
        return 1
    else:  # 불필요하지만 논리 구조를 뚜렷하게 해주는 else
        return f(n-1)+f(n-2)

result = f(6)
print(result)    #8이 출력됨

c = 0
def f(n):
    global c    # 로컬 c를 만들지 않고 글로벌 c를 쓰겠다는 명령
    if n == 7:
        c = c + 1
    if n == 1 or n == 2:
        return 1
    else:  # 불필요하지만 논리 구조를 뚜렷하게 해주는 else
        return f(n-1)+f(n-2)

result = f(20)
print(result)    # 6765
print(f'f(7)은 {c}번 호출됨') # f(7)은 377번 호출됨
